  'What is accounts receivable?': { prompt: "¿Qué son las cuentas por cobrar?", options: ["Dinero que debes a otros", "Dinero que te deben los clientes", "Tu saldo bancario", "Tu nómina"], correctAnswer: "Dinero que te deben los clientes" },
  'Invoicing clients 60 days after completing work.': { prompt: "Facturar a los clientes 60 días después de completar el trabajo.", options: ["Buena práctica", "Mala práctica"], correctAnswer: "Mala práctica" },
  'Cash flow problems are the number one reason small businesses fail.': { prompt: "Los problemas de flujo de caja son la razón número uno por la que los pequeños negocios fracasan.", options: ["Verdadero", "Falso"], correctAnswer: "Verdadero" },
  'What is a cash flow forecast?': { prompt: "¿Qué es un pronóstico de flujo de caja?", options: ["Un reporte del clima", "Una predicción de entradas y salidas de efectivo futuras", "Una lista de transacciones pasadas", "Una solicitud de préstamo"], correctAnswer: "Una predicción de entradas y salidas de efectivo futuras" },
  'Net 30 means the customer has ___ days to pay the invoice.': { prompt: "Net 30 significa que el cliente tiene ___ días para pagar la factura.", options: ["30", "60", "10", "90"], correctAnswer: "30" },
  'Which cash flow practice is better?': { prompt: "¿Qué práctica de flujo de caja es mejor?", options: ["Esperar hasta que el dinero se acabe para preocuparse por el flujo de caja.", "Pronosticar el flujo de caja semanalmente y planificar para déficits."], correctAnswer: "Pronosticar el flujo de caja semanalmente y planificar para déficits." },
  'Offering early payment discounts can improve cash flow.': { prompt: "Ofrecer descuentos por pago anticipado puede mejorar el flujo de caja.", options: ["Verdadero", "Falso"], correctAnswer: "Verdadero" },

  // Hiring
