  'What is onboarding?': { prompt: "¿Qué es el onboarding?", options: ["Un término de skateboarding", "El proceso de integrar a un nuevo empleado en la empresa", "Despedir a un empleado", "Un tipo de entrevista"], correctAnswer: "El proceso de integrar a un nuevo empleado en la empresa" },
