  'Which hiring approach is better?': { prompt: "¿Qué enfoque de contratación es mejor?", options: ["Contratar rápido, despedir rápido — solo pon a alguien en el puesto.", "Tomar tiempo para encontrar a la persona correcta que encaje en el puesto y la cultura."], correctAnswer: "Tomar tiempo para encontrar a la persona correcta que encaje en el puesto y la cultura." },
  'Remote hiring expands your talent pool beyond your local area.': { prompt: "La contratación remota expande tu grupo de talentos más allá de tu área local.", options: ["Verdadero", "Falso"], correctAnswer: "Verdadero" },

  // Leadership
  'What is the difference between a manager and a leader?': { prompt: "¿Cuál es la diferencia entre un gerente y un líder?", options: ["Son idénticos", "Los gerentes controlan procesos, los líderes inspiran personas", "Los líderes ganan menos", "Los gerentes siempre son mejores"], correctAnswer: "Los gerentes controlan procesos, los líderes inspiran personas" },
