  'Micromanaging every task your team does.': { prompt: "Microgestionar cada tarea que hace tu equipo.", options: ["Buena práctica", "Mala práctica"], correctAnswer: "Mala práctica" },
  'Leaders should admit mistakes to build trust with their team.': { prompt: "Los líderes deberían admitir errores para construir confianza con su equipo.", options: ["Verdadero", "Falso"], correctAnswer: "Verdadero" },
