  'Which leadership approach is better?': { prompt: "¿Qué enfoque de liderazgo es mejor?", options: ["Hazlo a mi manera o vete.", "Aquí está nuestro objetivo — ¿cómo crees que deberíamos llegar?"], correctAnswer: "Aquí está nuestro objetivo — ¿cómo crees que deberíamos llegar?" },
  'Great leaders are born, not made.': { prompt: "Los grandes líderes nacen, no se hacen.", options: ["Verdadero", "Falso"], correctAnswer: "Falso" },

  // Operations
  'What are business operations?': { prompt: "¿Qué son las operaciones de negocio?", options: ["Solo manufactura", "Las actividades diarias que mantienen un negocio funcionando", "Campañas de marketing", "Reuniones con inversores"], correctAnswer: "Las actividades diarias que mantienen un negocio funcionando" },
  'Standard Operating Procedures (SOPs) help ensure consistency.': { prompt: "Los Procedimientos Operativos Estándar (SOPs) ayudan a asegurar consistencia.", options: ["Verdadero", "Falso"], correctAnswer: "Verdadero" },
