  'What is a KPI?': { prompt: "¿Qué es un KPI?", options: ["Un tipo de moneda", "Un Indicador Clave de Rendimiento usado para medir el éxito", "Una herramienta de marketing", "Un tipo de software"], correctAnswer: "Un Indicador Clave de Rendimiento usado para medir el éxito" },
  'Documenting every important process in your business.': { prompt: "Documentar cada proceso importante en tu negocio.", options: ["Buena práctica", "Mala práctica"], correctAnswer: "Buena práctica" },
  'Efficient operations reduce costs and improve customer satisfaction.': { prompt: "Las operaciones eficientes reducen costos y mejoran la satisfacción del cliente.", options: ["Verdadero", "Falso"], correctAnswer: "Verdadero" },
  'What is supply chain management?': { prompt: "¿Qué es la gestión de la cadena de suministro?", options: ["Gestionar suministros de oficina", "Supervisar el flujo desde materias primas hasta la entrega final", "Encadenar suministros", "Un sistema de archivo"], correctAnswer: "Supervisar el flujo desde materias primas hasta la entrega final" },
  'Lean operations aim to minimize ___ while maximizing value.': { prompt: "Las operaciones lean buscan minimizar el ___ mientras maximizan el valor.", options: ["Desperdicio", "Personal", "Ingresos", "Productos"], correctAnswer: "Desperdicio" },
  'Which operations approach is better?': { prompt: "¿Qué enfoque de operaciones es mejor?", options: ["Cada quien hace las cosas a su manera.", "Procesos estandarizados con documentación clara."], correctAnswer: "Procesos estandarizados con documentación clara." },
  'Inventory management is part of business operations.': { prompt: "La gestión de inventario es parte de las operaciones de negocio.", options: ["Verdadero", "Falso"], correctAnswer: "Verdadero" },

  // Partnerships
  'What is a strategic partnership?': { prompt: "¿Qué es una alianza estratégica?", options: ["Un requisito legal", "Una relación mutuamente beneficiosa entre dos negocios", "Un acuerdo con competidores", "Un acuerdo de franquicia"], correctAnswer: "Una relación mutuamente beneficiosa entre dos negocios" },
  'Partnerships can help you reach new markets faster.': { prompt: "Las alianzas pueden ayudarte a llegar a nuevos mercados más rápido.", options: ["Verdadero", "Falso"], correctAnswer: "Verdadero" },
