  'What should every partnership have?': { prompt: "¿Qué debería tener toda alianza?", options: ["Nada, solo un apretón de manos", "Un acuerdo escrito que defina roles y responsabilidades", "Logos iguales", "Productos idénticos"], correctAnswer: "Un acuerdo escrito que defina roles y responsabilidades" },
  'Entering a partnership without a written agreement.': { prompt: "Entrar en una alianza sin un acuerdo escrito.", options: ["Buena práctica", "Mala práctica"], correctAnswer: "Mala práctica" },
  'Co-marketing is when two brands promote each other to their audiences.': { prompt: "El co-marketing es cuando dos marcas se promueven mutuamente a sus audiencias.", options: ["Verdadero", "Falso"], correctAnswer: "Verdadero" },
  'What is an affiliate partnership?': { prompt: "¿Qué es una alianza de afiliados?", options: ["Contratar un consultor", "Un socio gana comisión por referir clientes a ti", "Fusionar dos empresas", "Una colaboración en redes sociales"], correctAnswer: "Un socio gana comisión por referir clientes a ti" },
