  'Which partnership approach is better?': { prompt: "¿Qué enfoque de alianzas es mejor?", options: ["Asociarte con cualquiera que pregunte.", "Elegir socios cuyos valores y audiencia se alineen con los tuyos."], correctAnswer: "Elegir socios cuyos valores y audiencia se alineen con los tuyos." },
  'All partners must contribute equally in money to be fair.': { prompt: "Todos los socios deben contribuir igualmente en dinero para ser justos.", options: ["Verdadero", "Falso"], correctAnswer: "Falso" },

  // Funding
  'What is bootstrapping?': { prompt: "¿Qué es el bootstrapping?", options: ["Obtener un préstamo bancario", "Financiar tu negocio con ahorros personales e ingresos", "Salir a bolsa", "Crowdfunding"], correctAnswer: "Financiar tu negocio con ahorros personales e ingresos" },
  'Venture capital investors typically want equity in your company.': { prompt: "Los inversores de capital de riesgo típicamente quieren participación en tu empresa.", options: ["Verdadero", "Falso"], correctAnswer: "Verdadero" },
  'A ___ investor is an individual who funds early-stage startups.': { prompt: "Un inversor ___ es un individuo que financia startups en etapa temprana.", options: ["Ángel", "Demonio", "Fantasma", "Estrella"], correctAnswer: "Ángel" },
  'What is a seed round?': { prompt: "¿Qué es una ronda semilla?", options: ["Plantar semillas reales", "La primera ronda significativa de financiamiento de capital de riesgo", "La ronda final de financiamiento", "Un préstamo bancario"], correctAnswer: "La primera ronda significativa de financiamiento de capital de riesgo" },
  'Giving away 80% of your company equity in the first round.': { prompt: "Dar el 80% del capital de tu empresa en la primera ronda.", options: ["Buena práctica", "Mala práctica"], correctAnswer: "Mala práctica" },
  'Crowdfunding lets you raise money from many small contributors.': { prompt: "El crowdfunding te permite recaudar dinero de muchos pequeños contribuyentes.", options: ["Verdadero", "Falso"], correctAnswer: "Verdadero" },
  'What is dilution in startup funding?': { prompt: "¿Qué es la dilución en financiamiento de startups?", options: ["Diluir un producto", "La reducción del porcentaje de propiedad del fundador al emitir nuevas acciones", "Reducir el tamaño de tu equipo", "Bajar tus precios"], correctAnswer: "La reducción del porcentaje de propiedad del fundador al emitir nuevas acciones" },
