  'Revenue-based financing means repaying a percentage of monthly revenue.': { prompt: "El financiamiento basado en ingresos significa devolver un porcentaje de los ingresos mensuales.", options: ["Verdadero", "Falso"], correctAnswer: "Verdadero" },

  // Legal Basics
  'What is an LLC?': { prompt: "¿Qué es una LLC?", options: ["Un tipo de préstamo", "Una Compañía de Responsabilidad Limitada que protege activos personales", "Un término de marketing", "Un formulario de impuestos"], correctAnswer: "Una Compañía de Responsabilidad Limitada que protege activos personales" },
