  'What does IP stand for in business?': { prompt: "¿Qué significa IP en negocios?", options: ["Solo Internet Protocol", "Propiedad Intelectual — patentes, marcas, derechos de autor", "Plan de Inversión", "Proceso Interno"], correctAnswer: "Propiedad Intelectual — patentes, marcas, derechos de autor" },
  'Operating without any written contracts with clients or partners.': { prompt: "Operar sin contratos escritos con clientes o socios.", options: ["Buena práctica", "Mala práctica"], correctAnswer: "Mala práctica" },
