  'You need a privacy policy if you collect user data.': { prompt: "Necesitas una política de privacidad si recopilas datos de usuarios.", options: ["Verdadero", "Falso"], correctAnswer: "Verdadero" },

  // Scaling Up
  'What does scaling a business mean?': { prompt: "¿Qué significa escalar un negocio?", options: ["Hacerlo más pequeño", "Crecer los ingresos más rápido que los costos", "Contratar 1000 personas", "Mudarse a una oficina más grande"], correctAnswer: "Crecer los ingresos más rápido que los costos" },
  'You should scale before finding product-market fit.': { prompt: "Deberías escalar antes de encontrar el product-market fit.", options: ["Verdadero", "Falso"], correctAnswer: "Falso" },
  'Product-market ___ means your product satisfies a strong market demand.': { prompt: "El product-market ___ significa que tu producto satisface una fuerte demanda del mercado.", options: ["Fit", "Gap", "Test", "Loss"], correctAnswer: "Fit" },
  'What is a scalable business model?': { prompt: "¿Qué es un modelo de negocio escalable?", options: ["Uno que solo funciona localmente", "Uno que puede crecer ingresos sin aumentar proporcionalmente los costos", "Un modelo que requiere duplicar personal por cada nuevo cliente", "Un modelo que nunca cambia"], correctAnswer: "Uno que puede crecer ingresos sin aumentar proporcionalmente los costos" },
  'Scaling customer support by only adding more people instead of using systems.': { prompt: "Escalar el soporte al cliente solo agregando más personas en vez de usar sistemas.", options: ["Buena práctica", "Mala práctica"], correctAnswer: "Mala práctica" },
  'Systems and processes must be in place before scaling.': { prompt: "Los sistemas y procesos deben estar establecidos antes de escalar.", options: ["Verdadero", "Falso"], correctAnswer: "Verdadero" },
  'What is horizontal scaling?': { prompt: "¿Qué es la escalabilidad horizontal?", options: ["Crecer más alto", "Expandirse a nuevos mercados o líneas de productos", "Reducir precios", "Despedir empleados"], correctAnswer: "Expandirse a nuevos mercados o líneas de productos" },
  'Unit ___ are the direct costs associated with producing one unit of your product.': { prompt: "La ___ unitaria son los costos directos asociados con producir una unidad de tu producto.", options: ["Economía", "Precio", "Margen", "Factor"], correctAnswer: "Economía" },
  'Which scaling approach is better?': { prompt: "¿Qué enfoque de escalamiento es mejor?", options: ["Crecer lo más rápido posible a cualquier costo.", "Escalar estratégicamente con sistemas probados y economía unitaria."], correctAnswer: "Escalar estratégicamente con sistemas probados y economía unitaria." },
  'Scaling too fast without infrastructure is a common cause of startup failure.': { prompt: "Escalar demasiado rápido sin infraestructura es una causa común de fracaso de startups.", options: ["Verdadero", "Falso"], correctAnswer: "Verdadero" },

  // Automation (Business)
  'What is business automation?': { prompt: "¿Qué es la automatización de negocios?", options: ["Reemplazar todos los empleados con robots", "Usar tecnología para realizar tareas repetitivas sin esfuerzo manual", "Externalizar todo", "Comprar software caro"], correctAnswer: "Usar tecnología para realizar tareas repetitivas sin esfuerzo manual" },
  'Zapier and Make (Integromat) are popular automation tools.': { prompt: "Zapier y Make (Integromat) son herramientas de automatización populares.", options: ["Verdadero", "Falso"], correctAnswer: "Verdadero" },
  'Email ___ lets you send scheduled emails based on user actions.': { prompt: "La ___ de email te permite enviar emails programados basados en acciones del usuario.", options: ["Automatización", "Marketing", "Explosión", "Reenvío"], correctAnswer: "Automatización" },
  'Which task is best suited for automation?': { prompt: "¿Qué tarea es más adecuada para la automatización?", options: ["Decisiones de estrategia creativa", "Enviar emails de bienvenida a nuevos registros", "Negociar alianzas", "Lluvia de ideas para nuevos productos"], correctAnswer: "Enviar emails de bienvenida a nuevos registros" },
  'Automating your social media posting schedule.': { prompt: "Automatizar tu cronograma de publicaciones en redes sociales.", options: ["Buena práctica", "Mala práctica"], correctAnswer: "Buena práctica" },
  'You should automate a process before understanding it manually first.': { prompt: "Deberías automatizar un proceso antes de entenderlo manualmente primero.", options: ["Verdadero", "Falso"], correctAnswer: "Falso" },
  'What is a chatbot?': { prompt: "¿Qué es un chatbot?", options: ["Un tipo de robot", "Un programa automatizado que puede responder preguntas de clientes", "Una app de redes sociales", "Un personaje de videojuego"], correctAnswer: "Un programa automatizado que puede responder preguntas de clientes" },
  'A CRM system helps automate customer ___ management.': { prompt: "Un sistema CRM ayuda a automatizar la gestión de ___ del cliente.", options: ["Relaciones", "Ingresos", "Calificación", "Ranking"], correctAnswer: "Relaciones" },
  'Which automation approach is better?': { prompt: "¿Qué enfoque de automatización es mejor?", options: ["Automatizar todo desde el primer día.", "Identificar cuellos de botella repetitivos primero, luego automatizarlos."], correctAnswer: "Identificar cuellos de botella repetitivos primero, luego automatizarlos." },
  'Automation always eliminates the need for human oversight.': { prompt: "La automatización siempre elimina la necesidad de supervisión humana.", options: ["Verdadero", "Falso"], correctAnswer: "Falso" },

  // Exit Strategy
  'What is an exit strategy?': { prompt: "¿Qué es una estrategia de salida?", options: ["Un plan de escape de incendios", "Un plan para cómo los fundadores eventualmente dejarán o venderán el negocio", "Un plan de bancarrota", "Una estrategia de marketing"], correctAnswer: "Un plan para cómo los fundadores eventualmente dejarán o venderán el negocio" },
  'You should think about your exit strategy from the beginning.': { prompt: "Deberías pensar en tu estrategia de salida desde el principio.", options: ["Verdadero", "Falso"], correctAnswer: "Verdadero" },
