  'What is an IPO?': { prompt: "¿Qué es un IPO?", options: ["Internal Process Optimization", "Oferta Pública Inicial — listar acciones en una bolsa de valores", "Investor Priority Order", "International Partnership Office"], correctAnswer: "Oferta Pública Inicial — listar acciones en una bolsa de valores" },
  'Building a business that depends entirely on you personally.': { prompt: "Construir un negocio que depende completamente de ti personalmente.", options: ["Buena práctica", "Mala práctica"], correctAnswer: "Mala práctica" },
